namespace sv_10ac0d515d54498598e122ca9d552816.Models;

// Service contract records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; } = DateTime.Today;
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@* Step progress indicator showing all steps with current/completed/future states *@

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var state = GetStepState(step);
        <button class="step @state"
                disabled="@(state == "future")"
                @onclick="() => OnStepClicked(step)"
                aria-current="@(state == "current" ? "step" : null)">
            <span class="step-icon">
                @if (state == "completed")
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>
        @if (step < StepNames.Count - 1)
        {
            <span class="step-connector @(step < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepState(int step)
    {
        if (step == CurrentStep) return "current";
        if (step < CurrentStep) return "completed";
        return "future";
    }

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0.5rem 1rem;
    min-width: 100px;
    transition: opacity 0.2s;
}

.step.completed {
    cursor: pointer;
}

.step.completed:hover {
    opacity: 0.8;
}

.step.future {
    opacity: 0.4;
}

.step-icon {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    transition: all 0.2s;
}

.step.current .step-icon {
    background: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.step.completed .step-icon {
    background: #198754;
    border-color: #198754;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 0 0 40px;
    height: 2px;
    background: #dee2e6;
    margin-bottom: 1.5rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

