toolArgs.file_text:
.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0.5rem 1rem;
    min-width: 100px;
    transition: opacity 0.2s;
}

.step.completed {
    cursor: pointer;
}

.step.completed:hover {
    opacity: 0.8;
}

.step.future {
    opacity: 0.4;
}

.step-icon {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: white;
    color: #6c757d;
    transition: all 0.2s;
}

.step.current .step-icon {
    background: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.step.completed .step-icon {
    background: #198754;
    border-color: #198754;
    color: white;
}

.step-label {
    font-size: 0.8rem;
    color: #6c757d;
    text-align: center;
    white-space: nowrap;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 0 0 40px;
    height: 2px;
    background: #dee2e6;
    margin-bottom: 1.5rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

