{"file_text": "@* A single reference entry *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="reference-card">
    <div class="reference-header">
        <h5>Reference @(Index + 1)</h5>
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
        }
    </div>

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Full Name *</label>
            <input class="form-control" @bind="Reference.Name" @bind:event="oninput" placeholder="Reference name" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Relationship *</label>
            <input class="form-control" @bind="Reference.Relationship" @bind:event="oninput" placeholder="e.g. Former Manager" />
        </div>
    </div>

    <div class="row mb-3">
