arguments.file_text:
@* Step 1: Personal information form with email validation *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="step-content">
    <h3>Personal Information</h3>
    <p class="text-muted">Tell us about yourself.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="mb-3">
        <label class="form-label">Full Name *</label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email Address *</label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">This email address is not valid.</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone Number *</label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="mb-3">
        <label class="form-label">Address *</label>
        <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"
                  placeholder="123 Main St, City, State ZIP"></textarea>
    </div>

    <div class="step-buttons">
        <div></div>
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? errorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task HandleNext()
    {
        errorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isEmailValid)
            {
                emailInvalid = true;
                errorMessage = "The email address could not be validated.";
                return;
            }
        }
        finally
        {
            isValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 2: Dynamic list of work history entries *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="step-content">
    <h3>Work History</h3>
    <p class="text-muted">Add your relevant work experience.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="step-buttons">
        <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Please fill in company name and job title for all positions.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 3: References (2-3 entries) *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="step-content">
    <h3>References</h3>
    <p class="text-muted">Provide 2–3 professional references.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="step-buttons">
        <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@* Step 4: Cover letter with character count *@

<div class="step-content">
    <h3>Cover Letter</h3>
    <p class="text-muted">Write a cover letter to accompany your application.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="mb-3">
        <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
                  placeholder="Dear Hiring Manager..." maxlength="2000"></textarea>
        <div class="form-text text-end @(CoverLetter.Length > 2000 ? "text-danger" : "")">
            @CoverLetter.Length / 2000 characters
        </div>
    </div>

    <div class="step-buttons">
        <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            errorMessage = "Please write a cover letter.";
            return;
        }

        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@* Step 5: Read-only review of all data with submit *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="step-content">
    <h3>Review & Submit</h3>
    <p class="text-muted">Review your application before submitting.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @if (IsSubmitted)
    {
        <div class="alert alert-success text-center py-4">
            <h4 class="alert-heading">🎉 Application Submitted!</h4>
            <p class="mb-0">Your application has been received. Your confirmation ID is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Personal Information</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>

        <!-- Work History -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Work History</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-2 ps-2 border-start border-3">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <!-- References -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>References</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>

        <!-- Cover Letter -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Cover Letter</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        <div class="step-buttons">
            <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool isSubmitting;
    private string? errorMessage;

    public bool IsSubmitted { get; private set; }
    public int ApplicationId { get; private set; }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

.review-section {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.review-section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-section-header h5 {
    margin: 0;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 1rem;
    border-radius: 0.375rem;
    margin: 0;
}

