toolArgs.file_text:
@* Step 5: Read-only review of all data with submit *@
@using sv_10ac0d515d54498598e122ca9d552816.Models

<div class="step-content">
    <h3>Review & Submit</h3>
    <p class="text-muted">Review your application before submitting.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @if (IsSubmitted)
    {
        <div class="alert alert-success text-center py-4">
            <h4 class="alert-heading">🎉 Application Submitted!</h4>
            <p class="mb-0">Your application has been received. Your confirmation ID is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Personal Information</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>

        <!-- Work History -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Work History</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-2 ps-2 border-start border-3">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <!-- References -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>References</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>

        <!-- Cover Letter -->
        <div class="review-section">
            <div class="review-section-header">
                <h5>Cover Letter</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        <div class="step-buttons">
            <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private bool isSubmitting;
    private string? errorMessage;

    public bool IsSubmitted { get; private set; }
    public int ApplicationId { get; private set; }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

.review-section {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
}

.review-section-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-section-header h5 {
    margin: 0;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 1rem;
    border-radius: 0.375rem;
    margin: 0;
}

