@using sv_10ac0d515d54498598e122ca9d552816.Components.Pages.Apply
@using sv_10ac0d515d54498598e122ca9d552816.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1 class="text-center mb-4">Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   StepNames="stepNames"
                   OnStepSelected="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="UpdateCoverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        ApplicationService="ApplicationService"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep" />
            break;
    }
</div>

@code {
    private int currentStep;
    private readonly List<string> stepNames = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, stepNames.Count - 1);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;
    private void UpdateCoverLetter(string value) => coverLetter = value;
}

